const config = $('Read Config Sheet').all();
const configMap = {};
config.forEach(item => { configMap[item.json.category] = item.json; });

const batchSize = parseInt($('Batch Form Trigger').first().json['Number of ideas to generate']) || 10;
const categoryFocus = $('Batch Form Trigger').first().json['Category focus (leave blank for All)'] || 'All';
const allCats = ['SAT_MYTH', 'BRAIN_TEASER', 'NOTES_APP', 'COMIC', 'BEAGLE_EXPLAINS'];
const active = categoryFocus === 'All' ? allCats : [categoryFocus];

const guides = active.map(cat => {
  const guide = (configMap[cat] || {}).style_guide || '[No style guide — fill in Config sheet]';
  return '=== ' + cat + ' ===\n' + guide;
}).join('\n\n');

const system = [
  'You are the creative content strategist for Athena, an SAT prep platform.',
  '',
  'NON-NEGOTIABLE BRAND RULES:',
  '- Athena is a personalized TEACHER, never an AI product, dashboard, or analytics tool',
  '- Core outcome: Ohhhh... now I get it.',
  '- Mascot: A cute Beagle dog — curious, friendly, slightly goofy. The Beagle is the guide/student in content, never the product.',
  '- Primary audience: Parents aged 35-55 worried about SAT scores, college admissions, tutoring costs, their kid feeling stuck.',
  '- NEVER lead with: AI-powered, adaptive learning, algorithms, analytics, dashboards.',
  '',
  'CATEGORY STYLE GUIDES (for context only — do NOT repeat these back in your output, they are already stored separately):',
  guides,
  '',
  'CRITICAL INSTRUCTION FOR concept:',
  'Do NOT write a full image-generation prompt. Do NOT restate or summarize the style guide.',
  'Just write the specific creative content for this one idea — detailed enough that someone could generate the image from it later, but nothing about general style, palette, or layout (that already lives in the style guide).',
  'For multi-panel/carousel categories (COMIC, BEAGLE_EXPLAINS), write out each panel/beat in sequence, with the exact text/dialogue for each panel.',
  'For SAT_MYTH, include: the myth statement, the visual scene, and the insight line.',
  'For NOTES_APP, include the full note text verbatim.',
  'For BRAIN_TEASER, include the actual puzzle and its answer.',
  '',
  'CRITICAL JSON SAFETY: Since your output must be valid JSON, NEVER use double quotes (") for emphasis, sarcasm, or scare-quotes within concept text. Use single quotes for any inline emphasis instead. Reserve double quotes only for JSON string delimiters.',
  'OUTPUT: Respond with ONLY a raw JSON array. No markdown fences. No preamble. Each object must have exactly two fields: category (one of the active categories), concept (the detailed specific content described above — can be multiple sentences/paragraphs, but never the style guide itself).'
].join('\n');

const user = categoryFocus === 'All'
  ? 'Generate exactly ' + batchSize + ' content ideas distributed roughly evenly across: ' + active.join(', ') + '.'
  : 'Generate exactly ' + batchSize + ' content ideas for the ' + categoryFocus + ' category.';

return [{ json: { body: {
  model: 'claude-sonnet-4-6',
  max_tokens: 8000,
  system,
  messages: [{ role: 'user', content: user }]
} } }];

const raw = $json.content[0].text;

function safeParse(text) {
  let s = text.trim();
  s = s.replace(/^```json\s*/i, '').replace(/^```\s*/, '').replace(/\s*```$/, '').trim();
  try {
    return JSON.parse(s);
  } catch (e) {
    // Repair pass: find unescaped " characters that appear INSIDE a JSON string value
    // (i.e. not immediately preceded by \, and not adjacent to : , { } [ ] whitespace)
    // by escaping any " that isn't functioning as a structural JSON quote.
    const repaired = s.replace(/(?<!\\)"(?=(?:[^"\\]|\\.)*"(?:\s*[,\]}]))/g, (match, offset, str) => {
      // Only escape quotes that are clearly mid-word (surrounded by letters), not structural
      const before = str[offset - 1];
      const after = str[offset + 1];
      if (/[a-zA-Z]/.test(before) || /[a-zA-Z]/.test(after)) {
        return '\\"';
      }
      return match;
    });
    return JSON.parse(repaired);
  }
}

let ideas;
try {
  ideas = safeParse(raw);
} catch(e) {
  const match = e.message.match(/position (\d+)/);
  const pos = match ? parseInt(match[1]) : null;
  let context = 'position not found in error';
  if (pos !== null) {
    const start = Math.max(0, pos - 80);
    const end = Math.min(raw.length, pos + 80);
    context = raw.substring(start, end);
  }
  throw new Error('PARSE FAILED: ' + e.message + ' || CONTEXT AROUND ERROR: ' + context);
}

if (!Array.isArray(ideas)) throw new Error('Expected JSON array from Claude, got: ' + typeof ideas);

return ideas.map((idea, i) => ({
  json: Object.assign({}, idea, {
    idea_id: (idea.category || 'idea').toLowerCase() + '_' + Date.now() + '_' + i
  })
}));

const allIdeas = $input.all().map(i => i.json);

const system = [
  'You are a strict content quality reviewer for Athena SAT prep content. For each idea evaluate:',
  '2. Does it align with the Athena brand — personalized teacher, not AI product?',
  '3. Would it genuinely resonate with parents of high-schoolers or students feeling stuck?',
  '4. Is it fresh and not a tired SAT prep cliche?',
  '',
  'Return ONLY a raw JSON array, same length and same order as input. Each object: {idea_id, keep (boolean), reason (brief string)}. No markdown. No preamble.'
].join('\n');

return [{ json: { body: {
  model: 'claude-sonnet-4-6',
  max_tokens: 2000,
  system,
  messages: [{ role: 'user', content: 'Review and filter these ideas:\n' + JSON.stringify(allIdeas, null, 2) }]
} } }];

const raw = $json.content[0].text;

function safeParse(text) {
  let s = text.trim();
  s = s.replace(/^```json\s*/i, '').replace(/^```\s*/, '').replace(/\s*```$/, '').trim();
  return JSON.parse(s);
}

let decisions;
try {
  decisions = safeParse(raw);
} catch(e) {
  throw new Error('Filter response parse failed: ' + e.message);
}

const map = {};
decisions.forEach(d => { map[d.idea_id] = d; });

const originals = $('Parse Ideas JSON').all().map(i => i.json);

return originals.map(idea => {
  const d = map[idea.idea_id] || { keep: true, reason: 'no decision returned — defaulting to keep' };
  return { json: Object.assign({}, idea, { ai_keep: d.keep, ai_filter_reason: d.reason }) };
});
